// Verify fetchWeather returns an error Result (not a thrown exception) on API failure
async function testFetchWeatherResultError() {
  // Latitude 999 is far outside valid range (-90..90) — Open-Meteo returns 400
  const result = await functions.call('fetchWeather', 999, 999);

  // Should be a failure Result, not a thrown exception
  assert(result.ok === false, 'Result should not be ok for invalid coordinates');
  assert(result.error !== undefined, 'Result should have an error object');
  assert(result.error.code === 'WEATHER_API_ERROR', 'Error code should be WEATHER_API_ERROR');
  assert(typeof result.error.message === 'string', 'Error message should be a string');
  assert(result.error.message.length > 0, 'Error message should not be empty');
}
